import{bQ as i,aL as a,u as e,G as t}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"镜像管理","description":"","frontmatter":{},"headers":[],"relativePath":"09.容器化/04-镜像管理.md","filePath":"09.容器化/04-镜像管理.md","lastUpdated":null}'),n={name:"09.容器化/04-镜像管理.md"};function p(h,s,l,d,k,r){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="镜像管理" tabindex="-1">镜像管理 <a class="header-anchor" href="#镜像管理" aria-label="Permalink to &quot;镜像管理&quot;">​</a></h1><p>镜像管理处理的事情围绕一条主线：镜像从哪里来、怎么构建、怎么打标签、怎么清理、怎么迁移。容器运行问题里，有一部分其实不是容器问题，而是镜像来源不清楚、标签指向模糊、构建过程不可复现。</p><h2 id="镜像的分层" tabindex="-1">镜像的分层 <a class="header-anchor" href="#镜像的分层" aria-label="Permalink to &quot;镜像的分层&quot;">​</a></h2><p>Docker 镜像是分层的。每一层是一次文件系统变更——基础系统、安装依赖、复制应用文件、设置启动命令，各是一层。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TD%0A%20%20%20%20base%5B%22%E5%9F%BA%E7%A1%80%E7%B3%BB%E7%BB%9F%E5%B1%82%22%5D%20--%3E%20pkg%5B%22%E8%BD%AF%E4%BB%B6%E5%8C%85%E5%92%8C%E8%BF%90%E8%A1%8C%E6%97%B6%E5%B1%82%22%5D%0A%20%20%20%20pkg%20--%3E%20app%5B%22%E5%BA%94%E7%94%A8%E6%96%87%E4%BB%B6%E5%B1%82%22%5D%0A%20%20%20%20app%20--%3E%20conf%5B%22%E9%85%8D%E7%BD%AE%E5%92%8C%E5%90%AF%E5%8A%A8%E5%91%BD%E4%BB%A4%E5%B1%82%22%5D%0A%20%20%20%20conf%20--%3E%20image%5B%22%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20image%20--%3E%20container%5B%22%E5%AE%B9%E5%99%A8%E5%8F%AF%E5%86%99%E5%B1%82%22%5D%0A"></div><p>镜像层只读，容器运行时在镜像上面加一层可写层。容器里写入的新文件、修改的配置、临时日志都在这一层。删除容器时，可写层通常也随之消失。</p><p>查看镜像层信息：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> history</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.26</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 各层大小和构建指令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.26</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 入口命令、架构、环境变量等元数据</span></span></code></pre></div><p>镜像层多不一定坏，关键是大文件和构建缓存有没有留在最终镜像里。编译工具、包管理缓存、临时压缩包经常是镜像体积大的主要原因。</p><h2 id="标签和摘要" tabindex="-1">标签和摘要 <a class="header-anchor" href="#标签和摘要" aria-label="Permalink to &quot;标签和摘要&quot;">​</a></h2><p>镜像名的完整格式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>registry.example.com/library/nginx:1.26</span></span></code></pre></div><table tabindex="0"><thead><tr><th>部分</th><th>说明</th></tr></thead><tbody><tr><td><code>registry.example.com</code></td><td>镜像仓库地址，不写默认是 Docker Hub</td></tr><tr><td><code>library/nginx</code></td><td>命名空间和镜像名</td></tr><tr><td><code>1.26</code></td><td>标签</td></tr></tbody></table><p>标签是人给镜像起的名字，摘要 digest 是镜像内容的哈希。标签可以被重新指向，digest 永远对应同一种内容。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.26</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.26</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{{index .RepoDigests 0}}&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 查看镜像 digest</span></span></code></pre></div><p>生产发布记录里只写 <code>nginx:latest</code> 基本没有复盘价值。至少记录 <code>镜像名:版本标签</code>，关键服务再补 digest——回滚时能确认拉到的是同一个内容。</p><p>同一个镜像 ID 可以有多个标签。删掉一个标签不一定释放磁盘，只有没有容器和任何标签引用时，镜像层才可能被清理。</p><h2 id="拉取、打标签和删除" tabindex="-1">拉取、打标签和删除 <a class="header-anchor" href="#拉取、打标签和删除" aria-label="Permalink to &quot;拉取、打标签和删除&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis:7.2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tag</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis:7.2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/base/redis:7.2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> images</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/base/redis</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rmi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/base/redis:7.2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 只删本地标签，不影响远端仓库</span></span></code></pre></div><h2 id="docker-commit——临时保存现场" tabindex="-1">docker commit——临时保存现场 <a class="header-anchor" href="#docker-commit——临时保存现场" aria-label="Permalink to &quot;docker commit——临时保存现场&quot;">​</a></h2><p><code>docker commit</code> 把容器的当前文件系统保存成镜像：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -dit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> centos:7</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net-tools</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 容器里临时装排查工具</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/tmp/centos-nettools:debug</span></span></code></pre></div><p>commit 适合临时保存现场做排查，不适合作为长期构建方式。它不会记录每一步为什么这么改，也很难复现。正式镜像还是写 Dockerfile，把依赖、文件、用户和启动命令放进版本控制。</p><h2 id="构建上下文和-dockerignore" tabindex="-1">构建上下文和 .dockerignore <a class="header-anchor" href="#构建上下文和-dockerignore" aria-label="Permalink to &quot;构建上下文和 .dockerignore&quot;">​</a></h2><p>构建时最后那个 <code>.</code> 是构建上下文路径。Docker 会把整个目录发给构建器，目录里无关文件太多时，构建变慢，镜像里也可能误 COPY 进去不该进去的东西。</p><p><code>.dockerignore</code> 用来从构建上下文里排除文件：</p><div class="language-dockerignore vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerignore</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 版本库和本地缓存不需要进入构建上下文</span></span>
<span class="line"><span>.git</span></span>
<span class="line"><span>node_modules</span></span>
<span class="line"><span>*.log</span></span>
<span class="line"><span>tmp/</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 本地环境文件不要打进镜像</span></span>
<span class="line"><span>.env</span></span></code></pre></div><p><code>.dockerignore</code> 不是安全边界，但能防止误打包。配置密钥、备份包、测试数据这类东西要从构建上下文里排掉。</p><h2 id="镜像导入导出" tabindex="-1">镜像导入导出 <a class="header-anchor" href="#镜像导入导出" aria-label="Permalink to &quot;镜像导入导出&quot;">​</a></h2><p>离线环境用 <code>save/load</code> 迁移镜像：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.26</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> save</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.26</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx-1.26.tar</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 导出镜像层和标签</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx-1.26.tar</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 在离线机器导入</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> images</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre></div><p><code>docker export/import</code> 处理的是容器文件系统，不保留镜像历史和部分元数据。迁移正式镜像用 <code>save/load</code>，不是 <code>export/import</code>。</p><h2 id="镜像清理" tabindex="-1">镜像清理 <a class="header-anchor" href="#镜像清理" aria-label="Permalink to &quot;镜像清理&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> df</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 镜像、容器、volume、构建缓存的磁盘占用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 更细的逐项查看</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 清理没有标签且没有被容器引用的镜像层</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> builder</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 清理 buildx/buildkit 构建缓存</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 清理所有未使用对象</span></span></code></pre></div><p><code>docker system prune -a</code> 会清掉所有未被容器引用的镜像，范围很大。生产机器上清理前先看 <code>docker system df</code> 和运行中的容器，避免把回滚需要的镜像删掉。</p><h2 id="镜像管理的检查维度" tabindex="-1">镜像管理的检查维度 <a class="header-anchor" href="#镜像管理的检查维度" aria-label="Permalink to &quot;镜像管理的检查维度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>检查点</th></tr></thead><tbody><tr><td>来源</td><td>官方镜像、内部仓库、维护者、更新时间</td></tr><tr><td>版本</td><td>标签是否固定，是否记录 digest</td></tr><tr><td>构建</td><td>Dockerfile 是否可复现，是否有 <code>.dockerignore</code></td></tr><tr><td>大小</td><td>构建缓存、包管理缓存、编译工具是否留在最终镜像</td></tr><tr><td>安全</td><td>是否用 root、是否包含密钥、是否做漏洞扫描</td></tr><tr><td>清理</td><td>本地镜像、构建缓存、旧标签是否有保留策略</td></tr></tbody></table><p>镜像管理乱了以后，发布和回滚都会变得含糊。容器跑得再稳，也架不住镜像标签指向不清、构建过程不可复现。</p>`,38)])])}const F=i(n,[["render",p]]);export{c as __pageData,F as default};
